import React, { useEffect, useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import api from '../services/api';
import AddUserModal from './Admin/AddUserModal';

function AdminDashboard({ user, onLogout }) {
  const navigate = useNavigate();
  const [users, setUsers] = useState([]);
  const [loading, setLoading] = useState(true);
  const [showAddUserModal, setShowAddUserModal] = useState(false);
  const [currentPage, setCurrentPage] = useState(1);
  const [sortOrder, setSortOrder] = useState('asc'); // 'asc' or 'desc'
  const itemsPerPage = 2;

  const fetchUsers = async () => {
    try {
      const response = await api.get('/admin/all-users-with-activity/');
      setUsers(response.data);
    } catch (err) {
      console.error('Failed to fetch users', err);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchUsers();
  }, []);

  const handleLogout = async () => {
    try {
      await api.post('/logout/');
      onLogout();
      navigate('/login');
    } catch (error) {
      console.error('Logout failed', error);
    }
  };

  const handleUserAdded = () => {
    fetchUsers();
  };

  // Sort users alphabetically
  const sortedUsers = [...users].sort((a, b) => {
    if (sortOrder === 'asc') {
      return a.username.localeCompare(b.username);
    } else {
      return b.username.localeCompare(a.username);
    }
  });

  // Pagination
  const totalPages = Math.ceil(sortedUsers.length / itemsPerPage);
  const startIndex = (currentPage - 1) * itemsPerPage;
  const paginatedUsers = sortedUsers.slice(startIndex, startIndex + itemsPerPage);

  const toggleSortOrder = () => {
    setSortOrder(sortOrder === 'asc' ? 'desc' : 'asc');
    setCurrentPage(1);
  };

  const goToPage = (page) => {
    setCurrentPage(page);
  };

  return (
    <div style={styles.container}>
      <div style={styles.header}>
        <h2 style={styles.headerTitle}>Admin Dashboard - {user?.username}</h2>
        <button onClick={handleLogout} style={styles.logoutButton}>Logout</button>
      </div>

      {/* Navigation Links */}
      <div style={styles.navLinks}>
        <button onClick={() => setShowAddUserModal(true)} style={styles.addUserButton}>
          + Add New User
        </button>
        <Link to="/admin/leave-requests" style={styles.leaveRequestsLink}>
          View Leave Requests
        </Link>
      </div>

      {/* Users List with Pagination */}
      <div style={styles.usersSection}>
        <div style={styles.sectionHeader}>
          <h3 style={styles.sectionTitle}>All Users</h3>
          <button onClick={toggleSortOrder} style={styles.sortButton}>
            Sort {sortOrder === 'asc' ? '↓ A-Z' : '↑ Z-A'}
          </button>
        </div>

        {loading ? (
          <div style={styles.loading}>Loading users...</div>
        ) : (
          <>
            <div style={styles.usersList}>
              {paginatedUsers.map((userData) => (
                <div key={userData.id} style={styles.userCard}>
                  <div style={styles.userHeader}>
                    <strong style={styles.userName}>{userData.username}</strong>
                    {userData.is_staff && <span style={styles.adminBadge}>Admin</span>}
                  </div>
                  <div style={styles.userInfo}>
                    <div>{userData.first_name} {userData.last_name}</div>
                    <div style={styles.userEmail}>{userData.email || 'No email'}</div>
                  </div>
                  <div style={styles.statsGrid}>
                    <div style={styles.statItem}>
                      <span style={styles.statValue}>{userData.stats.total_attendance}</span>
                      <span style={styles.statLabel}>Present</span>
                    </div>
                    <div style={styles.statItem}>
                      <span style={styles.statValue}>{userData.stats.total_leave}</span>
                      <span style={styles.statLabel}>Leaves</span>
                    </div>
                    <div style={styles.statItem}>
                      <span style={styles.statValue}>{userData.stats.pending_leave}</span>
                      <span style={styles.statLabel}>Pending</span>
                    </div>
                    <div style={styles.statItem}>
                      <span style={styles.statValue}>{userData.stats.total_wfh}</span>
                      <span style={styles.statLabel}>WFH</span>
                    </div>
                  </div>
                </div>
              ))}
            </div>

            {/* Pagination Controls */}
            {totalPages > 1 && (
              <div style={styles.pagination}>
                <button
                  onClick={() => goToPage(currentPage - 1)}
                  disabled={currentPage === 1}
                  style={styles.pageButton}
                >
                  Previous
                </button>
                {[...Array(totalPages)].map((_, index) => (
                  <button
                    key={index + 1}
                    onClick={() => goToPage(index + 1)}
                    style={{
                      ...styles.pageNumber,
                      ...(currentPage === index + 1 ? styles.activePage : {})
                    }}
                  >
                    {index + 1}
                  </button>
                ))}
                <button
                  onClick={() => goToPage(currentPage + 1)}
                  disabled={currentPage === totalPages}
                  style={styles.pageButton}
                >
                  Next
                </button>
              </div>
            )}
          </>
        )}
      </div>

      {/* Add User Modal */}
      {showAddUserModal && (
        <AddUserModal
          onClose={() => setShowAddUserModal(false)}
          onUserAdded={handleUserAdded}
        />
      )}
    </div>
  );
}

const styles = {
  container: {
    padding: '30px',
    maxWidth: '1200px',
    margin: '0 auto',
  },
  header: {
    backgroundColor: 'var(--moss-dark)',
    color: 'white',
    padding: '20px 30px',
    borderRadius: '12px',
    marginBottom: '30px',
    display: 'flex',
    justifyContent: 'space-between',
    alignItems: 'center',
    boxShadow: '0 3px 8px rgba(0,0,0,0.2)',
  },
  headerTitle: {
    margin: 0,
    fontSize: '26px',
    fontWeight: 500,
  },
  logoutButton: {
    backgroundColor: 'var(--moss-pale)',
    color: 'var(--moss-dark)',
    border: 'none',
    padding: '8px 25px',
    borderRadius: '25px',
    fontSize: '16px',
    cursor: 'pointer',
    fontFamily: 'Times New Roman, Times, serif',
  },
  navLinks: {
    display: 'flex',
    gap: '15px',
    marginBottom: '30px',
  },
  addUserButton: {
    backgroundColor: 'var(--moss-green)',
    color: 'white',
    border: 'none',
    padding: '12px 24px',
    borderRadius: '8px',
    fontSize: '16px',
    cursor: 'pointer',
    fontFamily: 'Times New Roman, Times, serif',
  },
  leaveRequestsLink: {
    backgroundColor: 'var(--moss-pale)',
    color: 'var(--moss-dark)',
    textDecoration: 'none',
    padding: '12px 24px',
    borderRadius: '8px',
    fontSize: '16px',
    fontWeight: 500,
    border: '1px solid var(--moss-green)',
  },
  usersSection: {
    backgroundColor: 'white',
    borderRadius: '16px',
    padding: '25px',
    border: '2px solid var(--moss-green)',
  },
  sectionHeader: {
    display: 'flex',
    justifyContent: 'space-between',
    alignItems: 'center',
    marginBottom: '20px',
    borderBottom: '2px solid var(--moss-light)',
    paddingBottom: '10px',
  },
  sectionTitle: {
    margin: 0,
    fontSize: '22px',
    color: 'var(--moss-dark)',
  },
  sortButton: {
    backgroundColor: 'var(--moss-pale)',
    border: '1px solid var(--moss-green)',
    padding: '6px 12px',
    borderRadius: '6px',
    cursor: 'pointer',
    fontSize: '14px',
  },
  usersList: {
    display: 'flex',
    flexDirection: 'column',
    gap: '15px',
  },
  userCard: {
